/**
 * The U-CALM Journal — content module.
 *
 * WHY THIS LIVES HERE (and not in src/i18n/locales/*.json):
 *   Long-form article prose does not belong in the UI-string files. Those hold
 *   short interface labels and run through the locale pipeline; an essay does
 *   not. Each entry is authored in all four languages in-house (the house
 *   standard: U-CALM never ships English-only pages). Page CHROME — the index
 *   eyebrow/title/lead, "min read", "Back to the Journal" — stays in i18n under
 *   the "journal" key like every other page.
 *
 * KEYSTONE STATE (2026-06-14):
 *   Two exemplar entries are authored end-to-end (EN/DE/FR/IT) to prove the
 *   pattern on the Cloudflare preview. The remaining ten Lugano pieces in
 *   UCALM_Portfolio/04_Content/journal/ slot straight in here once the preview
 *   is confirmed — same shape, then add each slug to scripts/prerender.mjs,
 *   public/sitemap.xml and public/llms.txt (the runbook lists the steps).
 *
 * Place names: Lugano and Ticino are kept across all locales (brand proper
 * nouns); city exonyms are natural per language (Milano/Londra in IT, Mailand
 * in DE, Londres in FR). Flag for review if you prefer Tessin in DE/FR.
 */

export type JournalLocale = "en" | "de" | "fr" | "it";

export interface JournalBlock {
  /** h2 = sub-heading · p = paragraph · sign = "Consider it done." sign-off · note = small print */
  t: "h2" | "p" | "sign" | "note";
  x: string;
}

export interface JournalContent {
  title: string;
  dek: string;
  body: JournalBlock[];
}

export interface JournalEntry {
  slug: string;
  /** ISO date — drives <time>, display, and Article schema. */
  date: string;
  readingMin: number;
  /** Brand imagery slot id (see src/brand/imagery.ts) — reuses an enabled asset. */
  image: number;
  keywords: string[];
  locales: Record<JournalLocale, JournalContent>;
}

