const LOCALES: JournalLocale[] = ["en", "de", "fr", "it"];

/** Normalise an i18next language (e.g. "en-GB") to one of our four locales. */
export function journalLocale(lang: string | undefined): JournalLocale {
  const base = (lang || "en").slice(0, 2).toLowerCase() as JournalLocale;
  return LOCALES.includes(base) ? base : "en";
}

/** Entries newest-first, for the index. */
export function journalIndex(): JournalEntry[] {
  return [...journalEntries].sort((a, b) => (a.date < b.date ? 1 : -1));
}

export function getJournalEntry(slug: string | undefined): JournalEntry | undefined {
  return journalEntries.find((e) => e.slug === slug);
}

export function localizedEntry(entry: JournalEntry, lang: string | undefined): JournalContent {
  return entry.locales[journalLocale(lang)];
}
